/**
 * Error type for FFI.
 */
public enum IntercomError {

    
    
    case AudioError(message: String)
    
    case ConnectionError(message: String)
    
    case SignalingError(message: String)
    
    case NotConnected(message: String)
    
    case AlreadyConnected(message: String)
    
    case InvalidConfig(message: String)
    
    case Timeout(message: String)
    
    case Internal(message: String)
    
}


public struct FfiConverterTypeIntercomError: FfiConverterRustBuffer {
    typealias SwiftType = IntercomError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> IntercomError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .AudioError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .ConnectionError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .SignalingError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .NotConnected(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .AlreadyConnected(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .InvalidConfig(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 7: return .Timeout(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 8: return .Internal(
            message: try FfiConverterString.read(from: &buf)
        )
        

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: IntercomError, into buf: inout [UInt8]) {
        switch value {

        

        
        case .AudioError(_ /* message is ignored*/):
            writeInt(&buf, Int32(1))
        case .ConnectionError(_ /* message is ignored*/):
            writeInt(&buf, Int32(2))
        case .SignalingError(_ /* message is ignored*/):
            writeInt(&buf, Int32(3))
        case .NotConnected(_ /* message is ignored*/):
            writeInt(&buf, Int32(4))
        case .AlreadyConnected(_ /* message is ignored*/):
            writeInt(&buf, Int32(5))
        case .InvalidConfig(_ /* message is ignored*/):
            writeInt(&buf, Int32(6))
        case .Timeout(_ /* message is ignored*/):
            writeInt(&buf, Int32(7))
        case .Internal(_ /* message is ignored*/):
            writeInt(&buf, Int32(8))

        
        }
    }
}


