extension IntercomError: Error { }

// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Intercom events for FFI.
 */

public enum IntercomEvent {
    
    case connectionStateChanged(state: ConnectionState
    )
    case connected(roomId: String, userId: String
    )
    case disconnected(reason: String
    )
    case userJoined(user: UserInfo
    )
    case userLeft(userId: String
    )
    case userTalkStart(userId: String, channelId: String
    )
    case userTalkStop(userId: String
    )
    case channelCreated(channel: ChannelInfo
    )
    case channelDeleted(channelId: String
    )
    case talkStarted(channelId: String
    )
    case talkStopped
    case audioLevel(inputLevel: Float, outputLevel: Float
    )
    case error(message: String
    )
}


public struct FfiConverterTypeIntercomEvent: FfiConverterRustBuffer {
    typealias SwiftType = IntercomEvent

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> IntercomEvent {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .connectionStateChanged(state: try FfiConverterTypeConnectionState.read(from: &buf)
        )
        
        case 2: return .connected(roomId: try FfiConverterString.read(from: &buf), userId: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .disconnected(reason: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .userJoined(user: try FfiConverterTypeUserInfo.read(from: &buf)
        )
        
        case 5: return .userLeft(userId: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .userTalkStart(userId: try FfiConverterString.read(from: &buf), channelId: try FfiConverterString.read(from: &buf)
        )
        
        case 7: return .userTalkStop(userId: try FfiConverterString.read(from: &buf)
        )
        
        case 8: return .channelCreated(channel: try FfiConverterTypeChannelInfo.read(from: &buf)
        )
        
        case 9: return .channelDeleted(channelId: try FfiConverterString.read(from: &buf)
        )
        
        case 10: return .talkStarted(channelId: try FfiConverterString.read(from: &buf)
        )
        
        case 11: return .talkStopped
        
        case 12: return .audioLevel(inputLevel: try FfiConverterFloat.read(from: &buf), outputLevel: try FfiConverterFloat.read(from: &buf)
        )
        
        case 13: return .error(message: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: IntercomEvent, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .connectionStateChanged(state):
            writeInt(&buf, Int32(1))
            FfiConverterTypeConnectionState.write(state, into: &buf)
            
        
        case let .connected(roomId,userId):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(roomId, into: &buf)
            FfiConverterString.write(userId, into: &buf)
            
        
        case let .disconnected(reason):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .userJoined(user):
            writeInt(&buf, Int32(4))
            FfiConverterTypeUserInfo.write(user, into: &buf)
            
        
        case let .userLeft(userId):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(userId, into: &buf)
            
        
        case let .userTalkStart(userId,channelId):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(userId, into: &buf)
            FfiConverterString.write(channelId, into: &buf)
            
        
        case let .userTalkStop(userId):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(userId, into: &buf)
            
        
        case let .channelCreated(channel):
            writeInt(&buf, Int32(8))
            FfiConverterTypeChannelInfo.write(channel, into: &buf)
            
        
        case let .channelDeleted(channelId):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(channelId, into: &buf)
            
        
        case let .talkStarted(channelId):
            writeInt(&buf, Int32(10))
            FfiConverterString.write(channelId, into: &buf)
            
        
        case .talkStopped:
            writeInt(&buf, Int32(11))
        
        
        case let .audioLevel(inputLevel,outputLevel):
            writeInt(&buf, Int32(12))
            FfiConverterFloat.write(inputLevel, into: &buf)
            FfiConverterFloat.write(outputLevel, into: &buf)
            
        
        case let .error(message):
            writeInt(&buf, Int32(13))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


public func FfiConverterTypeIntercomEvent_lift(_ buf: RustBuffer) throws -> IntercomEvent {
    return try FfiConverterTypeIntercomEvent.lift(buf)
}

public func FfiConverterTypeIntercomEvent_lower(_ value: IntercomEvent) -> RustBuffer {
    return FfiConverterTypeIntercomEvent.lower(value)
}



